data.content:
Here's how to test `DataFetcher` with MSTest, covering success, failure, cancellation, and timeouts:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler("hello world", HttpStatusCode.OK);
        var sut = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await sut.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler("", HttpStatusCode.InternalServerError);
        var sut = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await sut.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange — handler that delays long enough for cancellation to fire
        var handler = new DelayHandler(TimeSpan.FromSeconds(30));
        var sut = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await sut.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // fail the test if it hangs
    public async Task FetchAsync_RespondsWithinTimeout_ReturnsContent()
    {
        var handler = new FakeHandler("fast", HttpStatusCode.OK);
        var sut = new DataFetcher(new HttpClient(handler));

        // Pass TestContext.CancellationToken so [Timeout] can cancel cooperatively
        var result = await sut.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    // --- Test helpers ---

    private sealed class FakeHandler(string content, HttpStatusCode status)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            var response = new HttpResponseMessage(status)
            {
                Content = new StringContent(content),
            };
            return Task.FromResult(response);
        }
    }

    private sealed class DelayHandler(TimeSpan delay) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(delay, cancellationToken);
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `sealed` test class | Performance + design clarity |
| Constructor-injected `TestContext` | Enables `readonly`, satisfies nullability |
| `Assert.ThrowsExactlyAsync<T>` | Replaces `[ExpectedException]` — lets you assert on the exact type |
| `[Timeout(5000)]` + `_testContext.CancellationToken` | Cooperative timeout — MSTest cancels the token when time expires |
| Custom `HttpMessageHandler` fakes | Avoids real HTTP calls; controls response content, status, and delay |

The critical detail: **always pass `TestContext.CancellationToken`** to async calls in tests with `[Timeout]`. Without it, the timeout attribute can't cancel a stuck operation cooperatively — it would have to abort the thread.
